import '../serialization/navivox_json.dart';

/// URI normalization helpers shared by Navivox pairing and setup flows.
const navivoxEndpointSchemes = {'http', 'https', 'ws', 'wss'};

bool navivoxIsEndpointScheme(String scheme) {
  return navivoxEndpointSchemes.contains(scheme.trim().toLowerCase());
}

String navivoxHttpSchemeFromEndpointScheme(
  String scheme, {
  String? descriptor,
}) {
  return switch (scheme.trim().toLowerCase()) {
    'ws' => 'http',
    'wss' => 'https',
    'http' => 'http',
    'https' => 'https',
    _ => throw FormatException(
      'Navivox endpoint URI must use ws, wss, http, or https',
      descriptor,
    ),
  };
}

String navivoxOriginFromUri(Uri uri) {
  return _navivoxOrigin(
    scheme: uri.scheme,
    host: uri.host,
    explicitPort: uri.hasPort ? uri.port : null,
  );
}

String _navivoxOrigin({
  required String scheme,
  required String host,
  required int? explicitPort,
}) {
  final formattedHost = host.contains(':') ? '[$host]' : host;
  final formattedPort = explicitPort == null ? '' : ':$explicitPort';
  return '$scheme://$formattedHost$formattedPort';
}

String navivoxHttpBaseUrlFromEndpointUri(Uri uri, {String? descriptor}) {
  final scheme = navivoxHttpSchemeFromEndpointScheme(
    uri.scheme,
    descriptor: descriptor,
  );
  if (uri.host.isEmpty) {
    throw FormatException(
      'Navivox endpoint URI must include a host',
      descriptor,
    );
  }
  return _navivoxOrigin(
    scheme: scheme,
    host: uri.host,
    explicitPort: uri.hasPort ? uri.port : null,
  );
}

String? navivoxHttpOriginOrOriginalFromString(String? raw) {
  final value = navivoxOptionalStringFromJson(raw);
  if (value == null) return null;
  final uri = Uri.tryParse(value);
  if (uri == null || !uri.hasScheme || uri.host.isEmpty) return value;
  final scheme = uri.scheme.toLowerCase();
  if (scheme != 'http' && scheme != 'https') return value;
  return navivoxOriginFromUri(uri);
}

Uri navivoxWebSocketUriFromEndpointString(String raw, {String? descriptor}) {
  final uri = Uri.parse(raw);
  if (uri.host.isEmpty) {
    throw FormatException(
      'Navivox websocket URI must include a host',
      descriptor,
    );
  }
  final scheme = uri.scheme.toLowerCase();
  if (scheme != 'ws' && scheme != 'wss') {
    throw FormatException(
      'Navivox websocket URI must use ws or wss',
      descriptor,
    );
  }
  return uri;
}

String? navivoxWebSocketUrlFromEndpointString(String? raw) {
  final value = navivoxOptionalStringFromJson(raw);
  if (value == null) return null;
  try {
    return navivoxWebSocketUriFromEndpointString(value).toString();
  } on FormatException {
    return null;
  }
}

String? navivoxHttpBaseUrlFromEndpointString(String? raw) {
  final uri = _endpointUriFromString(raw);
  if (uri == null || !navivoxIsEndpointScheme(uri.scheme)) return null;
  return navivoxHttpBaseUrlFromEndpointUri(uri);
}

Uri? _endpointUriFromString(String? raw) {
  final value = navivoxOptionalStringFromJson(raw);
  if (value == null) return null;
  final uri = Uri.tryParse(value);
  if (uri == null || !uri.hasScheme || uri.host.isEmpty) return null;
  return uri;
}

import 'navivox_endpoint_uri.dart';

void main() {
  derivesHttpOriginFromWebSocketEndpointWithoutDroppingExplicitPort();
  stripsPathAndQueryOnlyForHttpBaseUrlDerivation();
  preservesWebSocketPathAndQueryForConnectionEndpoint();
  keepsOriginalValueWhenHttpOriginCannotBeDerived();
}

void derivesHttpOriginFromWebSocketEndpointWithoutDroppingExplicitPort() {
  final result = navivoxHttpBaseUrlFromEndpointString(
    'wss://gateway.example:443/navivox/ws?token=secret',
  );

  _expect(
    result == 'https://gateway.example:443',
    'explicit default ports are part of the endpoint origin contract',
  );
}

void stripsPathAndQueryOnlyForHttpBaseUrlDerivation() {
  final result = navivoxHttpBaseUrlFromEndpointString(
    'https://gateway.example:8443/api?token=secret',
  );

  _expect(result == 'https://gateway.example:8443', 'base URL is origin only');
}

void preservesWebSocketPathAndQueryForConnectionEndpoint() {
  final result = navivoxWebSocketUrlFromEndpointString(
    'wss://gateway.example/navivox/ws?token=secret',
  );

  _expect(
    result == 'wss://gateway.example/navivox/ws?token=secret',
    'websocket endpoint keeps path/query while base URL derivation strips them',
  );
}

void keepsOriginalValueWhenHttpOriginCannotBeDerived() {
  final result = navivoxHttpOriginOrOriginalFromString(
    'ftp://gateway.example/resource',
  );

  _expect(
    result == 'ftp://gateway.example/resource',
    'non-HTTP values are preserved for compatibility instead of rejected',
  );
}

void _expect(bool condition, String message) {
  if (!condition) throw StateError(message);
}

import '../../gateway/client/navivox_gateway_config.dart';
import '../endpoint/navivox_endpoint_uri.dart';
import '../serialization/navivox_json.dart';

class NavivoxPairingDescriptor {
  const NavivoxPairingDescriptor({
    required this.baseUri,
    required this.webSocketUri,
    required this.authMode,
    required this.exposureMode,
    required this.tokenRequired,
    this.token,
    this.serverId,
    this.profileId,
    this.workspaceId,
    this.providerId,
    this.channelIds = const [],
  });

  factory NavivoxPairingDescriptor.parse(String value) {
    final uri = Uri.parse(value.trim());
    if (uri.scheme != 'navivox' || uri.host != 'connect') {
      throw FormatException('Expected navivox://connect descriptor', value);
    }
    final query = uri.queryParameters;
    final tokenRequired = _boolFromPairingParam(query['token_required']);
    final token = _optionalPairingParam(query['rest_token']);
    if (tokenRequired && token == null) {
      throw FormatException('Pairing descriptor requires rest_token', value);
    }
    final webSocketUri = navivoxWebSocketUriFromEndpointString(
      _requiredPairingParam(query, 'websocket_url', value),
      descriptor: value,
    );
    final baseUri = _baseUriFromPairingParams(
      explicitBaseUrl: _optionalPairingParam(query['base_url']),
      webSocketUri: webSocketUri,
      descriptor: value,
    );
    return NavivoxPairingDescriptor(
      baseUri: baseUri,
      webSocketUri: webSocketUri,
      authMode: _optionalPairingParam(query['auth_mode']) ?? '',
      exposureMode: _optionalPairingParam(query['exposure_mode']) ?? '',
      tokenRequired: tokenRequired,
      token: token,
      serverId: _optionalPairingParam(query['server_id']),
      profileId: _optionalPairingParam(query['profile_id']),
      workspaceId: _optionalPairingParam(query['workspace_id']),
      providerId: _optionalPairingParam(query['provider_id']),
      channelIds: _csvPairingParam(query['channel_ids']),
    );
  }

  final Uri baseUri;
  final Uri webSocketUri;
  final String authMode;
  final String exposureMode;
  final bool tokenRequired;
  final String? token;
  final String? serverId;
  final String? profileId;
  final String? workspaceId;
  final String? providerId;
  final List<String> channelIds;

  NavivoxGatewayConfig toGatewayConfig() {
    return NavivoxGatewayConfig(
      baseUri: baseUri,
      token: token,
      webSocketUri: webSocketUri,
    );
  }
}

String _requiredPairingParam(
  Map<String, String> query,
  String name,
  String descriptor,
) {
  final value = _optionalPairingParam(query[name]);
  if (value == null) {
    throw FormatException('Pairing descriptor missing $name', descriptor);
  }
  return value;
}

String? _optionalPairingParam(String? value) {
  return navivoxOptionalStringFromJson(value);
}

Uri _baseUriFromPairingParams({
  required String? explicitBaseUrl,
  required Uri webSocketUri,
  required String descriptor,
}) {
  if (explicitBaseUrl != null) {
    return _httpBaseUriFromPairingParam(explicitBaseUrl, descriptor);
  }
  return Uri.parse(_baseUrlFromWebSocketUri(webSocketUri, descriptor));
}

Uri _httpBaseUriFromPairingParam(String value, String descriptor) {
  final uri = Uri.parse(value);
  final scheme = uri.scheme.toLowerCase();
  if ((scheme != 'http' && scheme != 'https') || uri.host.isEmpty) {
    throw FormatException(
      'Pairing descriptor base_url must use http or https',
      descriptor,
    );
  }
  return uri;
}

String _baseUrlFromWebSocketUri(Uri uri, String descriptor) {
  try {
    return navivoxHttpBaseUrlFromEndpointUri(uri, descriptor: descriptor);
  } on FormatException {
    throw FormatException(
      'Pairing descriptor invalid websocket_url',
      descriptor,
    );
  }
}

bool _boolFromPairingParam(String? value) {
  return navivoxStrictBoolFromJson(value);
}

List<String> _csvPairingParam(String? value) {
  final trimmed = navivoxOptionalStringFromJson(value);
  if (trimmed == null) return const [];
  return navivoxTrimmedStringList(trimmed.split(','));
}

